import { Navigate } from 'react-router-dom';

// 1. Create a Protection Component
const ProtectedAdminRoute = ({ children }) => {
    const userRole = localStorage.getItem("user_role"); // This is set during login
    
    if (userRole !== "admin") {
        return <Navigate to="/login" replace />;
    }
    return children;
};

// 2. Update your Routes
<Route 
    path="/admin" 
    element={
        <ProtectedAdminRoute>
            <AdminDashboard />
        </ProtectedAdminRoute>
    } 
/>
